fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return 0;
    }

    let max_bit = 50;
    let mut depth = vec![0; max_bit + 1];

    for x in 1..(1 << max_bit) {
        let mut current = x;
        let mut d = 0;
        while current != 1 {
            current = current.count_ones();
            d += 1;
        }
        depth[x.bit_length()] = d;
    }

    let mut count = 0;
    for x in 1..=n {
        let bit_len = x.bit_length();
        if depth[bit_len] == k {
            count += 1;
        }
    }

    count
}
