fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return 0;
    }

    // Precompute the popcount-depth for numbers up to 50 bits
    // Since the maximum n is 1e15, which is less than 2^50, we can precompute up to 50 bits
    let max_bit = 50;
    let mut depth = vec![0; max_bit + 1];

    // Precompute the popcount-depth for all numbers up to 2^max_bit - 1
    for x in 1..(1 << max_bit) {
        let mut current = x;
        let mut d = 0;
        while current != 1 {
            current = current.count_ones();
            d += 1;
        }
        let bit_len = x.bit_length();
        depth[bit_len] = d;
    }

    // Now count how many numbers in [1, n] have popcount-depth exactly k
    let mut count = 0;
    for x in 1..=n {
        let bit_len = x.bit_length();
        let d = depth[bit_len];
        if d == k {
            count += 1;
        }
    }

    count
}
